        .with_columns(
        portfolio_size=assign_portfolio(x, "size", [0, 0.5, 1]),
        portfolio_bm=assign_portfolio(x, "bm", [0, 0.3, 0.7, 1])
        )
    )
    .select(["permno", "sorting_date", "portfolio_size", "portfolio_bm"])
)




